/**
 * Sport Icons - Icônes Bootstrap Icons pour chaque type de sport
 * Utilisé pour afficher les icônes des sports de combat de manière cohérente
 */

export const SPORT_ICONS = {
  boxe: 'hand-fist',           // Poing fermé - symbolise la boxe
  mma: 'person-arms-raised',   // Personne bras levés - symbolise la victoire en MMA
  kickboxing: 'leg',            // Jambe - symbolise les coups de pied
  judo: 'person',               // Personne générique - art martial personnel
  jjb: 'person-raised-hand',    // Personne main levée - symbolise le combat au sol
  autre: 'shield-check'         // Bouclier - générique protection/sport
};

/**
 * Crée une classe Bootstrap Icon appropriée
 * @param {string} type - Type de sport (boxe, mma, etc.)
 * @returns {string} - Classe CSS Bootstrap Icon
 */
export function getSportIconClass(type) {
  const iconName = SPORT_ICONS[type] || SPORT_ICONS.autre;
  return `bi-${iconName}`;
}

/**
 * Crée un composant icône sport réutilisable
 * @param {string} type - Type de sport
 * @param {string} size - Taille en pixels (défaut: 24)
 * @param {boolean} filled - Utiliser la version remplie si disponible
 * @returns {React.ReactElement} - Élément i avec l'icône
 */
export function SportIcon({ type = 'autre', size = '24', filled = false }) {
  const iconName = SPORT_ICONS[type] || SPORT_ICONS.autre;
  const iconClass = filled ? `bi-${iconName}-fill` : `bi-${iconName}`;
  
  return (
    <i 
      className={`bi ${iconClass}`} 
      style={{ fontSize: size, display: 'inline-block' }}
    />
  );
}

/**
 * Retourne la couleur associée à chaque type de sport
 */
export function getSportColor(type) {
  const colors = {
    boxe: '#DC2626',      // Rouge - agressivité
    mma: '#EA580C',       // Orange - puissance
    kickboxing: '#F59E0B', // Ambre - vitesse
    judo: '#3B82F6',      // Bleu - discipline
    jjb: '#8B5CF6',       // Violet - stratégie
    autre: '#6B7280'      // Gris - neutre
  };
  return colors[type] || colors.autre;
}

/**
 * Retourne la description d'un type de sport
 */
export function getSportDescription(type) {
  const descriptions = {
    boxe: 'Art martial basé sur les coups de poing',
    mma: 'Arts martiaux mixtes - Lutte complète',
    kickboxing: 'Combat avec coups de poing et coups de pied',
    judo: 'Art martial japonais - Projection et contrôle',
    jjb: 'Jiu-jitsu brésilien - Combat au sol',
    autre: 'Autre sport de combat'
  };
  return descriptions[type] || descriptions.autre;
}
